  // Expand/collapse library
  const [expandedLibraries, setExpandedLibraries] = useState({});

  const toggleLibrary = (libraryId) => {
    setExpandedLibraries(prev => ({
      ...prev,
      [libraryId]: !prev[libraryId]
    }));
