                      borderTop: '2px solid white',
                      borderRadius: '50%',
                      animation: 'spin 1s linear infinite'
                    }} />
                    Searching...
                  </div>
                ) : (
                  'Search Profiles'
                )}
              </button>

              {profiles.length > 0 && (
                <button
                  onClick={clearSearch}
                  style={{
                    padding: '16px 24px',
                    backgroundColor: 'transparent',
                    color: '#64748b',
                    border: '2px solid #64748b',
                    borderRadius: '16px',
                    fontSize: '16px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    transition: 'all 0.3s ease'
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.backgroundColor = '#64748b';
                    e.target.style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.backgroundColor = 'transparent';
                    e.target.style.color = '#64748b';
                  }}
                >
                  Clear Results
                </button>
              )}
            </div>
          </>
        )}

        {/* Error Display */}
        {error && (
          <div style={{
            background: 'linear-gradient(135deg, #fed7d7 0%, #feb2b2 100%)',
            color: '#c53030',
            padding: '16px 20px',
            borderRadius: '12px',
            marginBottom: '24px',
            fontSize: '14px',
            fontWeight: '500',
            border: '1px solid rgba(197, 48, 48, 0.2)',
            boxShadow: '0 4px 12px rgba(197, 48, 48, 0.1)',
            display: 'flex',
            alignItems: 'center',
            gap: '12px'
          }}>
            <div style={{
              width: '20px',
              height: '20px',
              borderRadius: '50%',
              background: '#c53030',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'white',
              fontSize: '12px',
              fontWeight: 'bold'
            }}>
              !
            </div>
            {error}
          </div>
        )}
      </div>

      {/* Search Results */}
      {view === 'search' && profiles.length > 0 && (
        <div style={{
          backgroundColor: 'rgba(255, 255, 255, 0.95)',
          backdropFilter: 'blur(20px)',
          borderRadius: '20px',
          padding: '32px',
          boxShadow: '0 20px 40px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(255, 255, 255, 0.2)',
          border: '1px solid rgba(255, 255, 255, 0.3)'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            marginBottom: '24px'
          }}>
            <div style={{
              width: '32px',
              height: '32px',
              background: 'linear-gradient(135deg, #1e3a8a 0%, #1e40af 100%)',
              borderRadius: '8px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '16px'
            }}>
              👥
            </div>
            <h2 style={{
              fontSize: '24px',
              fontWeight: '700',
              background: 'linear-gradient(135deg, #1e3a8a 0%, #64748b 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              margin: 0
            }}>
              Profiles Found ({profiles.length})
            </h2>
          </div>

          <div style={{
            display: 'grid',
            gap: '16px'
          }}>
            {profiles.map((profile, index) => (
              <div
                key={index}
                style={{
                  background: 'rgba(255, 255, 255, 0.8)',
                  backdropFilter: 'blur(10px)',
                  border: '1px solid rgba(30, 58, 138, 0.1)',
                  borderRadius: '12px',
                  padding: '20px',
                  transition: 'all 0.3s ease',
                  boxShadow: '0 4px 12px rgba(0, 0, 0, 0.05)'
                }}
                onMouseEnter={(e) => {
                  e.target.style.transform = 'translateY(-2px)';
                  e.target.style.boxShadow = '0 8px 24px rgba(30, 58, 138, 0.15)';
                  e.target.style.borderColor = 'rgba(30, 58, 138, 0.3)';
                }}
                onMouseLeave={(e) => {
                  e.target.style.transform = 'translateY(0)';
                  e.target.style.boxShadow = '0 4px 12px rgba(0, 0, 0, 0.05)';
                  e.target.style.borderColor = 'rgba(30, 58, 138, 0.1)';
                }}
              >
                <div style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'flex-start',
                  gap: '16px'
                }}>
                  <div style={{ flex: 1 }}>
                    <h3 style={{
                      fontSize: '18px',
                      fontWeight: '700',
                      color: '#1e293b',
                      margin: '0 0 8px 0',
                      lineHeight: '1.4'
                    }}>
                      {profile.name}
                    </h3>

                    {profile.headline && (
                      <p style={{
                        fontSize: '16px',
                        fontWeight: '600',
                        color: '#1e3a8a',
                        margin: '0 0 8px 0',
                        lineHeight: '1.4'
                      }}>
                        {profile.headline}
                      </p>
                    )}

                    {profile.summary && (
                      <p style={{
                        fontSize: '14px',
                        color: '#4a5568',
                        lineHeight: '1.6',
                        margin: 0
                      }}>
                        {profile.summary}
                      </p>
                    )}
                  </div>

                  <div style={{
                    display: 'flex',
                    flexDirection: 'column',
                    gap: '8px',
                    minWidth: '120px'
                  }}>
                    <button
                      onClick={() => saveProfile(profile)}
                      style={{
                        padding: '8px 16px',
                        backgroundColor: '#10b981',
                        color: 'white',
                        border: 'none',
                        borderRadius: '8px',
                        fontSize: '12px',
                        fontWeight: '600',
                        cursor: 'pointer',
                        transition: 'all 0.2s',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: '6px'
                      }}
                      onMouseEnter={(e) => {
                        e.target.style.backgroundColor = '#059669';
                        e.target.style.transform = 'translateY(-1px)';
                      }}
                      onMouseLeave={(e) => {
                        e.target.style.backgroundColor = '#10b981';
                        e.target.style.transform = 'translateY(0)';
                      }}
                    >
                      💾 Save Profile
                    </button>

                    {profile.profileUrl && (
                      <button
                        onClick={() => window.open(profile.profileUrl, '_blank')}
                        style={{
                          padding: '8px 16px',
                          backgroundColor: '#1e3a8a',
                          color: 'white',
                          border: 'none',
                          borderRadius: '8px',
                          fontSize: '12px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '6px'
                        }}
                        onMouseEnter={(e) => {
                          e.target.style.backgroundColor = '#1e40af';
                          e.target.style.transform = 'translateY(-1px)';
                        }}
                        onMouseLeave={(e) => {
                          e.target.style.backgroundColor = '#1e3a8a';
                          e.target.style.transform = 'translateY(0)';
                        }}
                      >
                        🔗 Open
                      </button>
                    )}

                    {profile.profileUrl && (
                      <button
                        onClick={() => {
                          navigator.clipboard.writeText(profile.profileUrl);
                          setError('Profile link copied to clipboard!');
                          setTimeout(() => setError(''), 2000);
                        }}
                        style={{
                          padding: '8px 16px',
                          backgroundColor: 'transparent',
                          color: '#1e3a8a',
                          border: '1px solid #1e3a8a',
                          borderRadius: '8px',
                          fontSize: '12px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '6px'
                        }}
                        onMouseEnter={(e) => {
                          e.target.style.backgroundColor = '#1e3a8a';
                          e.target.style.color = 'white';
                          e.target.style.transform = 'translateY(-1px)';
                        }}
                        onMouseLeave={(e) => {
                          e.target.style.backgroundColor = 'transparent';
                          e.target.style.color = '#1e3a8a';
                          e.target.style.transform = 'translateY(0)';
                        }}
                      >
                        📋 Copy Link
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Saved Profiles */}
      {view === 'saved' && (
        <div style={{
          backgroundColor: 'rgba(255, 255, 255, 0.95)',
          backdropFilter: 'blur(20px)',
          borderRadius: '20px',
          padding: '32px',
          boxShadow: '0 20px 40px rgba(0, 0, 0, 0.1), 0 0 0 1px rgba(255, 255, 255, 0.2)',
          border: '1px solid rgba(255, 255, 255, 0.3)'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            marginBottom: '24px'
          }}>
            <div style={{
              width: '32px',
              height: '32px',
              background: 'linear-gradient(135deg, #1e3a8a 0%, #1e40af 100%)',
              borderRadius: '8px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '16px'
            }}>
              💾
            </div>
            <h2 style={{
              fontSize: '24px',
              fontWeight: '700',
              background: 'linear-gradient(135deg, #1e3a8a 0%, #64748b 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              margin: 0
            }}>
              Saved Profiles ({getFilteredSavedProfiles().length}
              {savedProfilesSearchQuery && savedProfiles.length !== getFilteredSavedProfiles().length && ` of ${savedProfiles.length}`})
            </h2>
          </div>

          {/* Search Input for Saved Profiles */}
          {savedProfiles.length > 0 && (
            <div style={{ marginBottom: '24px', position: 'relative' }}>
              <input
                type="text"
                value={savedProfilesSearchQuery}
                onChange={(e) => setSavedProfilesSearchQuery(e.target.value)}
                placeholder="Search by name, company, title, location..."
                style={{
                  width: '100%',
                  padding: '12px 16px 12px 44px',
                  border: '2px solid #e2e8f0',
                  borderRadius: '12px',
                  fontSize: '14px',
                  outline: 'none',
                  transition: 'all 0.2s',
                  boxSizing: 'border-box',
                  backgroundColor: 'white'
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = '#4299e1';
                  e.target.style.boxShadow = '0 0 0 3px rgba(66, 153, 225, 0.1)';
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = '#e2e8f0';
                  e.target.style.boxShadow = 'none';
                }}
              />
              <div style={{
                position: 'absolute',
                left: '14px',
                top: '50%',
                transform: 'translateY(-50%)',
                fontSize: '18px',
                color: '#4299e1'
              }}>
                🔍
              </div>
              {savedProfilesSearchQuery && (
                <button
                  onClick={() => setSavedProfilesSearchQuery('')}
                  style={{
                    position: 'absolute',
                    right: '12px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    background: 'transparent',
                    border: 'none',
                    fontSize: '18px',
                    cursor: 'pointer',
                    padding: '4px',
                    color: '#718096'
                  }}
                >
                  ✕
                </button>
              )}
            </div>
          )}

          {savedProfiles.length === 0 ? (
            <div style={{
              textAlign: 'center',
              padding: '48px 20px',
              color: '#64748b'
            }}>
              <div style={{
                fontSize: '48px',
                marginBottom: '16px'
              }}>
                📋
              </div>
              <h3 style={{
                fontSize: '18px',
                fontWeight: '600',
                color: '#374151',
                marginBottom: '8px'
              }}>
                No saved profiles yet
              </h3>
              <p style={{
                fontSize: '14px',
                color: '#64748b',
                margin: 0
              }}>
                Search for profiles and save them for outreach planning
              </p>
            </div>
          ) : getFilteredSavedProfiles().length === 0 ? (
            <div style={{
              textAlign: 'center',
              padding: '48px 20px',
              color: '#64748b'
            }}>
              <div style={{
                fontSize: '48px',
                marginBottom: '16px'
              }}>
                🔍
              </div>
              <h3 style={{
                fontSize: '18px',
                fontWeight: '600',
                color: '#374151',
                marginBottom: '8px'
              }}>
                No profiles match your search
              </h3>
              <p style={{
                fontSize: '14px',
                color: '#64748b',
                margin: 0
              }}>
                Try different keywords or <span style={{ color: '#4299e1', cursor: 'pointer' }} onClick={() => setSavedProfilesSearchQuery('')}>clear search</span>
              </p>
            </div>
          ) : (
            <div style={{
              display: 'grid',
              gap: '20px'
            }}>
              {getFilteredSavedProfiles().map((profile, index) => (
                <div
                  key={index}
                  style={{
                    background: 'rgba(255, 255, 255, 0.8)',
                    backdropFilter: 'blur(10px)',
                    border: '1px solid rgba(30, 58, 138, 0.1)',
                    borderRadius: '16px',
                    padding: '24px',
                    transition: 'all 0.3s ease',
                    boxShadow: '0 4px 12px rgba(0, 0, 0, 0.05)'
                  }}
                >
                  <div style={{
                    display: 'flex',
                    alignItems: 'flex-start',
                    gap: '16px'
                  }}>
                    {profile.imageUrl && (
                      <img
                        src={profile.imageUrl}
                        alt={profile.name}
                        style={{
                          width: '64px',
                          height: '64px',
                          borderRadius: '12px',
                          objectFit: 'cover',
                          border: '2px solid rgba(30, 58, 138, 0.1)'
                        }}
                      />
                    )}

                    <div style={{ flex: 1 }}>
                      <div style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'flex-start',
                        marginBottom: '8px'
                      }}>
                        <h3 style={{
                          fontSize: '18px',
                          fontWeight: '700',
                          color: '#1e293b',
                          margin: 0,
                          lineHeight: '1.4'
                        }}>
                          {profile.name}
                        </h3>
                        <div style={{
                          display: 'flex',
                          gap: '8px'
                        }}>
                          {profile.profileUrl && (
                            <button
                              onClick={() => window.open(profile.profileUrl, '_blank')}
                              style={{
                                padding: '6px 12px',
                                backgroundColor: '#1e3a8a',
                                color: 'white',
                                border: 'none',
                                borderRadius: '6px',
                                fontSize: '12px',
                                fontWeight: '600',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '4px'
                              }}
                              onMouseEnter={(e) => {
                                e.target.style.backgroundColor = '#1e40af';
                                e.target.style.transform = 'translateY(-1px)';
                              }}
                              onMouseLeave={(e) => {
                                e.target.style.backgroundColor = '#1e3a8a';
                                e.target.style.transform = 'translateY(0)';
                              }}
                            >
                              🔗 Open
                            </button>
                          )}

                          {profile.profileUrl && (
                            <button
                              onClick={() => {
                                navigator.clipboard.writeText(profile.profileUrl);
                                setError('Profile link copied to clipboard!');
                                setTimeout(() => setError(''), 2000);
                              }}
                              style={{
                                padding: '6px 12px',
                                backgroundColor: 'transparent',
                                color: '#1e3a8a',
                                border: '1px solid #1e3a8a',
                                borderRadius: '6px',
                                fontSize: '12px',
                                fontWeight: '600',
                                cursor: 'pointer',
                                transition: 'all 0.2s',
                                display: 'flex',
                                alignItems: 'center',
                                gap: '4px'
                              }}
                              onMouseEnter={(e) => {
                                e.target.style.backgroundColor = '#1e3a8a';
                                e.target.style.color = 'white';
                                e.target.style.transform = 'translateY(-1px)';
                              }}
                              onMouseLeave={(e) => {
                                e.target.style.backgroundColor = 'transparent';
                                e.target.style.color = '#1e3a8a';
                                e.target.style.transform = 'translateY(0)';
                              }}
                            >
                              📋 Copy
                            </button>
                          )}

                          <button
                            onClick={() => removeSavedProfile(profile.id)}
                            style={{
                              padding: '6px 12px',
                              backgroundColor: '#ef4444',
                              color: 'white',
                              border: 'none',
                              borderRadius: '6px',
                              fontSize: '12px',
                              fontWeight: '600',
                              cursor: 'pointer',
                              transition: 'all 0.2s'
                            }}
                            onMouseEnter={(e) => {
                              e.target.style.backgroundColor = '#dc2626';
                              e.target.style.transform = 'translateY(-1px)';
                            }}
                            onMouseLeave={(e) => {
                              e.target.style.backgroundColor = '#ef4444';
                              e.target.style.transform = 'translateY(0)';
                            }}
                          >
                            Remove
                          </button>
                        </div>
                      </div>

                      {profile.headline && (
                        <p style={{
                          fontSize: '16px',
                          fontWeight: '600',
                          color: '#1e3a8a',
                          margin: '0 0 8px 0',
                          lineHeight: '1.4'
                        }}>
                          {profile.headline}
                        </p>
                      )}

                      <div style={{
                        display: 'flex',
                        gap: '16px',
                        marginBottom: '12px',
                        fontSize: '14px',
                        color: '#64748b'
                      }}>
                        {profile.location && (
                          <span>📍 {profile.location}</span>
                        )}
                        {profile.company && (
                          <span>🏢 {profile.company}</span>
                        )}
                        {profile.connections && (
                          <span>🔗 {profile.connections}</span>
                        )}
                      </div>

                      <div style={{
                        fontSize: '12px',
                        color: '#9ca3af',
                        marginTop: '8px'
                      }}>
                        Saved on {new Date(profile.savedAt).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

export default LinkedInSearchWidget;
